{
var seed = GetInt(parameters, "seed", context.Seed);
var shape = GetChoice(parameters, "shape", "round");
var size = GetFloat(parameters, "size", 0.6f);
var roughness = GetFloat(parameters, "roughness", 0.5f);
var colorVariations = Math.Max(1, GetInt(parameters, "colorVariations", 3));
var mainColor = GetColor(parameters, "mainColor", Color.FromRgb(140, 130, 120));
var highlightColor = GetColor(parameters, "highlightColor", Color.FromRgb(180, 170, 155));
var shadowColor = GetColor(parameters, "shadowColor", Color.FromRgb(80, 75, 70));
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var mR = mainColor.R / 255f; var mG = mainColor.G / 255f; var mB = mainColor.B / 255f;
var hR = highlightColor.R / 255f; var hG = highlightColor.G / 255f; var hB = highlightColor.B / 255f;
var sR = shadowColor.R / 255f; var sG = shadowColor.G / 255f; var sB = shadowColor.B / 255f;

var halfSize = tileSize * 0.5f;
var radius = halfSize * size;
var rockSeed = seed;

// Shape-specific parameters
var aspectY = shape switch
{
    "flat" => 0.5f,
    "sharp" => 1.2f,
    _ => 1f
};

buffer.ParallelForEachPixel((x, y) =>
{
    var cx = x + 0.5f - halfSize;
    var cy = (y + 0.5f - halfSize) / aspectY;
    var dist = MathF.Sqrt(cx * cx + cy * cy);
    var maxDist = radius;

    // Voronoi-based organic distortion for rock shape
    var cells = 4;
    var cellSize = maxDist * 2f / cells;
    var nearest = float.MaxValue;
    var secondNearest = float.MaxValue;
    var nearestCellX = 0;
    var nearestCellY = 0;

    // Convert to cell-space for Voronoi sampling
    var u = (cx + maxDist) / (maxDist * 2f);
    var v = (cy + maxDist * aspectY) / (maxDist * 2f * aspectY);

    for (var dy = -1; dy <= 1; dy++)
    {
        for (var dx = -1; dx <= 1; dx++)
        {
            var cellX = (int)MathF.Floor(u * cells) + dx;
            var cellY = (int)MathF.Floor(v * cells) + dy;
            var jx = HashToUnit(cellX, cellY, rockSeed) - 0.5f;
            var jy = HashToUnit(cellX, cellY, rockSeed + 37) - 0.5f;
            var pX = (cellX + 0.5f + jx * roughness) / cells;
            var pY = (cellY + 0.5f + jy * roughness) / cells;
            var dX = u - pX;
            var dY = v - pY * 1f / aspectY;
            var d = dX * dX + dY * dY;
            if (d < nearest)
            {
                secondNearest = nearest;
                nearest = d;
                nearestCellX = cellX;
                nearestCellY = cellY;
            }
            else if (d < secondNearest)
                secondNearest = d;
        }
    }

    var voronoiEdge = MathF.Sqrt(secondNearest) - MathF.Sqrt(nearest);

    // Base shape: circle/ellipse with Voronoi perturbation
    var shapeDist = dist / maxDist;
    var perturbation = (nearest / (cellSize * cellSize)) * roughness * 0.3f;
    var rockShape = shapeDist + perturbation;
    var alpha = 1f - SmoothStep(0.8f, 1.2f, rockShape);
    if (alpha <= 0.01f)
    {
        buffer.SetPixel(x, y, 0, 0, 0, 0);
        return;
    }

    // Internal detail: cracks and crevices using cell-based color variation
    var cellHash = HashToUnit(nearestCellX, nearestCellY, rockSeed + 100);
    var colorIdx = (int)(cellHash * colorVariations);
    var variation = (colorIdx / (float)Math.Max(1, colorVariations - 1)) * 2f - 1f;

    // Edge intensity: stronger near Voronoi cell boundaries
    var edgeFactor = Math.Clamp(voronoiEdge * 2f, 0f, 1f);

    // Lighting: highlight from top-left, stronger on flatter areas
    var lightAngle = MathF.Atan2(cy * aspectY + 0.01f, cx + 0.01f);
    var lightDir = MathF.Cos(lightAngle + MathF.PI * 0.25f) * 0.5f + 0.5f;
    var edgeWear = MathF.Sqrt(edgeFactor);

    // Combine color = base + variation + lighting
    var t = alpha;
    var height = 1f - shapeDist;
    var light = Math.Clamp(lightDir * height * 1.5f + 0.3f, 0f, 1f) * (1f - edgeWear * 0.3f);

    // Blend between shadow, main, and highlight
    float finalR, finalG, finalB;
    if (light < 0.5f)
    {
        var lt = light * 2f;
        finalR = Lerp(sR, mR, lt) + variation * 0.05f;
        finalG = Lerp(sG, mG, lt) + variation * 0.05f;
        finalB = Lerp(sB, mB, lt) + variation * 0.05f;
    }
    else
    {
        var lt = (light - 0.5f) * 2f;
        finalR = Lerp(mR, hR, lt) + variation * 0.05f;
        finalG = Lerp(mG, hG, lt) + variation * 0.05f;
        finalB = Lerp(mB, hB, lt) + variation * 0.05f;
    }

    // Brightness/contrast adjustment
    if (MathF.Abs(contrast) > 0.001f || MathF.Abs(brightness) > 0.001f)
    {
        var f = 1f + contrast;
        finalR = (finalR - 0.5f) * f + 0.5f + brightness;
        finalG = (finalG - 0.5f) * f + 0.5f + brightness;
        finalB = (finalB - 0.5f) * f + 0.5f + brightness;
    }

    buffer.SetPixel(x, y,
        Math.Clamp(finalR, 0f, 1f),
        Math.Clamp(finalG, 0f, 1f),
        Math.Clamp(finalB, 0f, 1f), alpha);
});

return buffer;
}
